# CA policy: require phishing-resistant MFA for all global administrators
New-MgIdentityConditionalAccessPolicy -BodyParameter @{
    DisplayName = 'CA: Global Admins - Phishing-Resistant MFA'
    State = 'enabled'
    Conditions = @{
        Users = @{
            IncludeRoles = @(
                '62e90394-69f5-4237-9190-012177145e10',  # Global Administrator
                'e8611ab8-c189-46e8-94e1-60213ab1f814',  # Privileged Role Administrator
                '194ae4cb-b126-40b2-bd5b-6091b380977d',  # Security Administrator
                'f28a1f50-f6e7-4571-818b-6a12f2af6b6c',  # SharePoint Administrator
            )
        }
        Applications = @{ IncludeApplications = @('All') }
        ClientAppTypes = @('all')
    }
    GrantControls = @{
        Operator = 'OR'
        AuthenticationStrength = @{
            Id = '00000000-0000-0000-0000-000000000004'  # Phishing-resistant MFA
        }
    }
}

# CA policy: use custom strength for specific app
New-MgIdentityConditionalAccessPolicy -BodyParameter @{
    DisplayName = 'CA: Finance Portal - Hardware-only MFA'
    State = 'enabled'
    Conditions = @{
        Users = @{ IncludeGroups = @('<finance-group-id>') }
        Applications = @{ IncludeApplications = @('<finance-portal-app-id>') }
        ClientAppTypes = @('all')
    }
    GrantControls = @{
        Operator = 'OR'
        AuthenticationStrength = @{
            Id = '<custom-hardware-only-strength-id>'
        }
    }
}

# Migrate existing CA policies from 'mfa' built-in control to authentication strength
# This is additive — auth strength gives finer control but does not break existing sessions

$policies = (Invoke-MgGraphRequest -Method GET \
    -Uri 'https://graph.microsoft.com/v1.0/identity/conditionalAccess/policies' \
    -OutputType PSObject).value

foreach ($policy in $policies) {
    $grant = $policy.grantControls
    if ($null -eq $grant) { continue }
    if ($grant.builtInControls -notcontains 'mfa') { continue }
    if ($grant.authenticationStrength) { continue }  # already migrated

    Write-Host "Candidate for migration: $($policy.displayName) [$($policy.id)]"
}

# To migrate a specific policy, PATCH it:
# Remove 'mfa' from builtInControls and add authenticationStrength
$patchBody = @{
    GrantControls = @{
        Operator = 'OR'
        BuiltInControls = @()  # remove 'mfa'
        AuthenticationStrength = @{
            Id = '00000000-0000-0000-0000-000000000002'  # MFA (equivalent to 'mfa' built-in)
        }
    }
} | ConvertTo-Json -Depth 5

Invoke-MgGraphRequest -Method PATCH \
    -Uri "https://graph.microsoft.com/v1.0/identity/conditionalAccess/policies/<policy-id>" \
    -Body $patchBody -ContentType 'application/json'

# Terraform: create custom authentication strength
resource "azuread_authentication_strength_policy" "hardware_mfa" {
  display_name = "Hardware-only MFA"
  description  = "FIDO2 and WHfB only"

  allowed_combinations = [
    "fido2",
    "windowsHelloForBusiness",
    "x509CertificateMultiFactor",
  ]
}

# Reference in CA policy grant controls
resource "azuread_conditional_access_policy" "admin_phish_resistant" {
  display_name = "CA: Admins - Hardware MFA"
  state        = "enabled"

  conditions {
    users { included_roles = ["62e90394-69f5-4237-9190-012177145e10"] }
    applications { included_applications = ["All"] }
    client_app_types = ["all"]
  }

  grant_controls {
    operator = "OR"
    authentication_strength_policy_id = azuread_authentication_strength_policy.hardware_mfa.id
  }
}
